const client = $('Process Data').item.json;
const report = $json.choices[0].message.content;
const monthName = client.monthName;
const reportHtml = report.replace(/\n/g, '<br>').replace(/\*\*(.*?)\*\*/g, '<b>$1</b>').replace(/\*(.*?)\*/g, '<em>$1</em>');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333;background:#f5f5f5;">
<div style="background:linear-gradient(135deg,#0d1b2a,#1a237e);padding:30px;border-radius:12px 12px 0 0;text-align:center;">
  <h1 style="color:#ffd700;margin:0;font-size:22px;">Galaxy IT & Marketing</h1>
  <p style="color:rgba(255,255,255,0.7);margin:8px 0 0;font-size:14px;">Monthly Performance Report</p>
  <p style="color:rgba(255,255,255,0.5);margin:4px 0 0;font-size:12px;">${monthName}</p>
</div>
<div style="background:#fff;padding:10px 30px;border-left:1px solid #e5e5e5;border-right:1px solid #e5e5e5;">
  <div style="display:flex;gap:10px;margin:20px 0;text-align:center;">
    <div style="flex:1;background:#f8f9fa;padding:14px 8px;border-radius:8px;border-top:3px solid #ffd700;">
      <div style="font-size:22px;font-weight:800;color:#1a237e;">${client.totalContacts}</div>
      <div style="font-size:10px;color:#888;margin-top:2px;">Contacts</div>
    </div>
    <div style="flex:1;background:#f8f9fa;padding:14px 8px;border-radius:8px;border-top:3px solid #2e7d32;">
      <div style="font-size:22px;font-weight:800;color:#1a237e;">${client.topSources.split(',')[0]?.split(':')[1]?.trim() || '—'}</div>
      <div style="font-size:10px;color:#888;margin-top:2px;">Top Source</div>
    </div>
  </div>
</div>
<div style="background:#fff;padding:0 30px 30px;border:1px solid #e5e5e5;border-top:none;">
  <p style="font-size:14px;line-height:1.8;">${reportHtml}</p>
</div>
<div style="background:#f8f9fa;padding:20px;border-radius:0 0 12px 12px;text-align:center;border:1px solid #e5e5e5;border-top:none;">
  <p style="margin:0;font-size:12px;color:#888;">Questions? <a href="https://galaxyinfo.us/support" style="color:#1a237e;font-weight:600;">Visit our Help Center</a> or reply to this email.</p>
  <p style="margin:8px 0 0;font-size:11px;color:#aaa;">&copy; 2026 Galaxy IT & Marketing &middot; Worcester, MA</p>
</div>
</body></html>`;

let wa = '\ud83d\udcca *Monthly Report — ' + monthName + '*\n';
wa += '*' + client.name + '*\n\n';
wa += '\ud83d\udc65 ' + client.totalContacts + ' contacts in CRM\n';
wa += '\ud83d\udcc8 Top sources: ' + client.topSources + '\n';
wa += '\ud83d\udcbb Website: ' + client.site + '\n\n';
wa += 'Full report sent to your email!';

return [{ json: { ...client, report, html, wa, monthName } }];

